import{c as t,Q as a,j as i,m as n}from"./chunks/framework.BBA2dIOt.js";const u=JSON.parse('{"title":"Web Push notifications","description":"","frontmatter":{},"headers":[],"relativePath":"notifications.md","filePath":"notifications.md","lastUpdated":1780679900000}'),o={name:"notifications.md"};function s(r,e,l,c,h,d){return a(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="web-push-notifications" tabindex="-1">Web Push notifications <a class="header-anchor" href="#web-push-notifications" aria-label="Permalink to &quot;Web Push notifications&quot;">​</a></h1><div class="info custom-block"><p class="custom-block-title">Coming in a future release</p><p>Browser push notifications (Web Push / VAPID) are <strong>in active development</strong> and are not part of the current <code>v0.7.x-beta</code> stream. This page is a placeholder while the implementation stabilizes.</p></div><h2 id="what-s-planned" tabindex="-1">What&#39;s planned <a class="header-anchor" href="#what-s-planned" aria-label="Permalink to &quot;What&#39;s planned&quot;">​</a></h2><ul><li>Opt-in per browser / installed PWA from <strong>Settings → Notifications</strong>.</li><li>VAPID keypair auto-generated and persisted server-side — no third-party push gateway.</li><li>Test-send button to verify the round trip.</li><li>A <code>notify</code> action in the rules engine that fires a push when a matching article arrives.</li></ul><h2 id="requirements-once-it-ships" tabindex="-1">Requirements once it ships <a class="header-anchor" href="#requirements-once-it-ships" aria-label="Permalink to &quot;Requirements once it ships&quot;">​</a></h2><ul><li>A <strong>trusted TLS certificate</strong>. Service workers refuse to register over self-signed / <code>tls internal</code> certificates, so push, offline cache, and PWA install all break together on a homelab deployment without a real cert. The doc that lands with the feature will walk through the DNS-01 / Let&#39;s Encrypt path for LAN-only deployments.</li></ul><h2 id="tracking" tabindex="-1">Tracking <a class="header-anchor" href="#tracking" aria-label="Permalink to &quot;Tracking&quot;">​</a></h2><p>Implementation lives on the <code>develop</code> branch. Follow the milestone or open issues at <a href="https://github.com/brandonhon/ember/issues" target="_blank" rel="noreferrer">https://github.com/brandonhon/ember/issues</a> for progress.</p>',8)])])}const f=t(o,[["render",s]]);export{u as __pageData,f as default};
